const s=document.getElementById("main-nav"),e=document.getElementById("hamburger"),n=document.getElementById("nav-links");window.addEventListener("scroll",()=>{s.classList.toggle("nav--scrolled",window.scrollY>60)},{passive:!0});e.addEventListener("click",()=>{const t=n.classList.toggle("nav-links-row--open");e.setAttribute("aria-expanded",String(t)),e.classList.toggle("hamburger--open",t)});n.querySelectorAll("a").forEach(t=>{t.addEventListener("click",()=>{n.classList.remove("nav-links-row--open"),e.setAttribute("aria-expanded","false"),e.classList.remove("hamburger--open")})});
